from azure.ai.projects import AgentClient

@vex_middleware
async def policy_validator(ctx, next):
    tool_call = ctx.request.tool_call

    # Block restricted endpoints
    restricted_endpoints = ['delete-', 'admin-', 'suspicious-']
    if any(endpoint in tool_call.function.name for endpoint in restricted_endpoints):
        return {'blocked': True, 'reason': 'Policy violation'}

    # Scan arguments for jailbreak patterns
    risk_score = VexMonitor.prompt_risk(tool_call.arguments)
    if risk_score > 0.8:
        ctx.request.tool_call.arguments = VexMonitor.sanitize(tool_call.arguments)

    return await next(ctx)

from azure.ai.projects.retrievers import BingRetriever, FileRetriever

class SafeGroundingRetriever:
    def __init__(self):
        self.bing = BingRetriever()
        self.file_search = FileRetriever()

    async def search(self, query: str):
        raw_results = await self.bing.search(query)

        safe_results = []
        for result in raw_results:
            if not VexMonitor.contains_jailbreak(result.content):
                # Strip Azure metadata
                clean_content = self._strip_azure_metadata(result.content)
                safe_results.append({
                    'content': clean_content,
                    'url': result.url
                })
        return safe_results[:3]
